import React, { Component } from 'react';
import data from './../Json/data';

const jsonData = data.main;
class About extends Component {
  render() {

    if(jsonData){
      var name = jsonData.name;
      var profilepic= "./images/"+jsonData.image;
      var bio = jsonData.bio;
      var street = jsonData.address.street;
      var city = jsonData.address.city;
      var state = jsonData.address.state;
      var zip = jsonData.address.zip;
      var phone= jsonData.phone;
      var email = jsonData.email;
      var resumeDownload = jsonData.resumedownload;
    }

    return (
      <section id="contact-cta" style={{ background: '#191919', padding: '100px 0', color: '#fff', textAlign: 'center' }}>
      <div className="row">
         <div className="twelve columns main-col">
            <h2 alt="Obrigado!" style={{ font: 'bold 32px/1.2 "opensans-bold", sans-serif', color: '#fff', textTransform: 'uppercase', letterSpacing: '1.5px', marginBottom: '20px' }}>
              Vamos Conversar?
            </h2>

            <p alt="Se você chegou até aqui, talvez eu tenha algo a contribuir com o seu projeto. No rodapé estão as formas de entrar em contato comigo, prometo responder o mais breve possível!" 
               className="text-adjust" 
               style={{ font: '16px/1.8 "opensans-regular", sans-serif', color: '#a0a0a0', maxWidth: '800px', margin: '0 auto 40px auto' }}>
              Se você chegou até aqui, talvez eu tenha algo a contribuir com o seu projeto. Sinta-se à vontade para entrar em contato comigo por e-mail ou LinkedIn — prometo responder o mais breve possível!
            </p>
            
            <div style={{ display: 'flex', justifyContent: 'center', gap: '20px', flexWrap: 'wrap', marginBottom: '40px' }}>
              {/* E-mail contact badge */}
              <a href={`mailto:${email}?subject=[VIA WEBSITE] Entrando em contato`} style={{
                background: 'rgba(255, 255, 255, 0.03)',
                border: '1px solid rgba(255, 255, 255, 0.1)',
                borderRadius: '12px',
                padding: '20px 30px',
                minWidth: '220px',
                textDecoration: 'none',
                color: '#fff',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
                transition: 'transform 0.3s ease, border-color 0.3s ease'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-5px)';
                e.currentTarget.style.borderColor = '#11ABB0';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.borderColor = 'rgba(255, 255, 255, 0.1)';
              }}
              >
                <i className="fa fa-envelope" style={{ fontSize: '28px', color: '#11ABB0', marginBottom: '10px' }}></i>
                <span style={{ fontWeight: 'bold', fontSize: '15px' }}>E-mail</span>
                <span style={{ fontSize: '13px', color: '#888', marginTop: '4px' }}>{email}</span>
              </a>

              {/* LinkedIn contact badge */}
              <a href="https://www.linkedin.com/in/rodrigooo" target="_blank" rel="noopener noreferrer" style={{
                background: 'rgba(255, 255, 255, 0.03)',
                border: '1px solid rgba(255, 255, 255, 0.1)',
                borderRadius: '12px',
                padding: '20px 30px',
                minWidth: '220px',
                textDecoration: 'none',
                color: '#fff',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
                transition: 'transform 0.3s ease, border-color 0.3s ease'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-5px)';
                e.currentTarget.style.borderColor = '#11ABB0';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.borderColor = 'rgba(255, 255, 255, 0.1)';
              }}
              >
                <i className="fa fa-linkedin-square" style={{ fontSize: '28px', color: '#11ABB0', marginBottom: '10px' }}></i>
                <span style={{ fontWeight: 'bold', fontSize: '15px' }}>LinkedIn</span>
                <span style={{ fontSize: '13px', color: '#888', marginTop: '4px' }}>rodrigooo</span>
              </a>
            </div>

            <div className="row">
               <div className="twelve columns" style={{ textAlign: 'center', marginTop: '20px' }}>
                  <a href={resumeDownload} className="button no-underline" target="_blank" rel="noopener noreferrer" style={{ display: 'inline-block', margin: '0 auto' }}>
                    <i className="fa fa-download" style={{ marginRight: '10px' }}></i>Baixar currículo completo
                  </a>
               </div>
            </div>
         </div>
      </div>
   </section>
    );
  }
}

export default About;
